/*
 * acos() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly acos  (test_acos_opt.elf)
 *   2. Linked with toolchain's default acos       (test_acos_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x)
{
    double r = acos(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0);
    emit(-0.0);

    /* NaN */
    emit_u(0x7ff8000000000000ULL); /* qNaN */
    emit_u(0x7ff0000000000001ULL); /* sNaN */
    emit_u(0xfff8000000000000ULL); /* -NaN */
}

/* 2. Tiny values */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL); /* min denorm */
    emit_u(0x8000000000000001ULL);
    emit_u(0x0008000000000000ULL); /* mid denorm */
    emit_u(0x8008000000000000ULL);
    emit_u(0x000fffffffffffffULL); /* max denorm */
    emit_u(0x800fffffffffffffULL);
    emit(DBL_MIN);
    emit(-DBL_MIN);
    emit(1.0e-200);
    emit(-1.0e-200);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    emit(1.0);
    emit(0.8660254);
    emit(0.7071068);
    emit(0.5);
    emit(0.0);
    emit(-0.5);
    emit(-0.7071068);
    emit(-0.8660254);
    emit(-1.0);
}

/* 4. Boundary values */
static void test_large(void)
{
    emit_u(0x3ff0000000000001ULL);  /* 1.0 + eps */
    emit_u(0xbff0000000000001ULL);  /* -1.0 - eps */
    emit(2.0);
    emit(-2.0);
    emit(1.5);
    emit(-1.5);
    emit(DBL_MAX);
    emit(-DBL_MAX);
}

/* 5. Normal range values */
static void test_quadrant(void)
{
    double vals[] = { -0.99, -0.9, -0.5, -0.1, 0.0, 0.1, 0.5, 0.9, 0.99 };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 6. Hard values near boundaries */
static void test_hard(void)
{
    double cases[] = {
        u2d(0x3fe921fb54442d18ULL), /* 0.7853981... (pi/4 normalized) */
        u2d(0x3ff0000000000000ULL), /* 1.0 */
        u2d(0x3fefffffff600000ULL), /* 1.0 - small epsilon */
        u2d(0xbff0000000000000ULL), /* -1.0 */
        u2d(0xbfefffffff600000ULL), /* -1.0 + small epsilon */
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        emit(-cases[i]);
    }
}

/* 7. Sweep [-1, 1] in 200 steps */
static void test_sweep(void)
{
    int nsteps = 200;
    double step = 2.0 / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(-1.0 + (double)i * step);
}

/* 8. Sample [0, 0.5] every 4503599627370496 ULP (~50 cases) */
static void test_exhaustive_small(void)
{
    uint64_t end = 0x3fe0000000000000ULL; /* 0.5 */
    for (uint64_t b = 0; b <= end; b += 4503599627370496ULL)
        emit_u(b);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -1.0;
    double hi =  1.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}
