/* 7. Sweep [-pi/4, pi/4] in 200 steps */
static void test_sweep(void)
{
    float pi_4 = 0.78539816339744830962f;
    int nsteps = 200;
    float step = 2.0f * pi_4 / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(-pi_4 + (float)i * step);
