/*
 * exp() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly exp    (test_exp_opt.elf)
 *   2. Linked with toolchain's default exp         (test_exp_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x)
{
    double r = exp(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0);
    emit(-0.0);

    /* NaN */
    emit_u(0x7ff8000000000000ULL); /* qNaN */
    emit_u(0x7ff0000000000001ULL); /* sNaN */
    emit_u(0xfff8000000000000ULL); /* -NaN */

    /* Infinity */
    emit_u(0x7ff0000000000000ULL); /* +Inf */
    emit_u(0xfff0000000000000ULL); /* -Inf */
}

/* 2. Tiny values: exp(x) near 1 */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL); /* min denorm */
    emit_u(0x8000000000000001ULL);
    emit_u(0x0008000000000000ULL); /* mid denorm */
    emit_u(0x8008000000000000ULL);
    emit_u(0x000fffffffffffffULL); /* max denorm */
    emit_u(0x800fffffffffffffULL);
    emit(DBL_MIN);
    emit(-DBL_MIN);
    emit(1.0e-200);
    emit(-1.0e-200);
    emit(1.0e-100);
    emit(-1.0e-100);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    emit(0.0);      /* exp(0) = 1 */
    emit(1.0);      /* exp(1) = e */
    emit(2.0);      /* exp(2) */
    emit(-1.0);     /* exp(-1) = 1/e */
    emit(-2.0);     /* exp(-2) */
    emit(0.5);      /* exp(0.5) = sqrt(e) */
    emit(-0.5);     /* exp(-0.5) */
    emit(10.0);     /* large positive */
    emit(-10.0);    /* large negative */
}

/* 4. Underflow/overflow boundary */
static void test_large(void)
{
    double vals[] = {
        -745.0,  /* near underflow boundary */
        -744.0,
        -700.0,
        -100.0,
        100.0,
        700.0,
        708.0,   /* near overflow boundary */
        709.0,   /* overflow boundary */
        -1000.0, /* deep underflow */
        1000.0,  /* deep overflow */
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Critical near-zero region where exp(x) ~ 1+x */
static void test_quadrant(void)
{
    double tiny_vals[] = {
        1.0e-20, 1.0e-15, 1.0e-10, 1.0e-5,
        -1.0e-20, -1.0e-15, -1.0e-10, -1.0e-5,
    };
    int n = sizeof(tiny_vals) / sizeof(tiny_vals[0]);
    for (int i = 0; i < n; i++)
        emit(tiny_vals[i]);
}

/* 6. Worst-case hard cases near overflow */
static void test_hard(void)
{
    double cases[] = {
        u2d(0x40862E42FEFA39EULL), /* ln(2)*128 ~ overflow threshold */
        u2d(0x40862E42FEFA39EULL) - 1.0,
        u2d(0x40862E42FEFA39EULL) + 1.0,
        709.7,   /* just below overflow */
        709.8,   /* oscillating near threshold */
        -745.1,  /* just below underflow */
        -745.2,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        if (cases[i] > 0.0)
            emit(-cases[i]);
    }
}

/* 7. Sweep [-100, 100] in 200 steps each */
static void test_sweep(void)
{
    double hi = 100.0;
    int nsteps = 200;
    double step = (2.0 * hi) / (double)nsteps;

    /* [-100, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);

    /* [0, 100] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}

/* 8. Sample [0, 1] every 2^47 ULP (~256 cases) */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fc0000000000000ULL, /* 0.125 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fd8000000000000ULL, /* 0.375 */
        0x3fe0000000000000ULL, /* 0.5 */
        0x3fe4000000000000ULL, /* 0.625 */
        0x3fe8000000000000ULL, /* 0.75 */
        0x3ff0000000000000ULL, /* 1.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    double lo = -10.0;
    double hi =  10.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile double acc = 0.0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += exp(x+i);
    stopPFM;
    readResult();
    printf("perf %016llx: %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u((double)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.0);
#else
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_quadrant();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

