#ifdef EN_PERF
static void perf(double x)
{
    volatile double acc = 0.0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += log10(x+i);
    stopPFM;
    readResult();
    printf("perf %016llx: %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u((double)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(2.0);
#else
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_quadrant();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

