/*
 * log10f() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly log10f  (test_log10f_opt.elf)
 *   2. Linked with toolchain's default log10f        (test_log10f_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifndef EN_PERF
static void emit(float x)
{
    float r = log10f(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f);
    emit(-0.0f);

    /* NaN */
    emit_u(0x7fc00000u); /* qNaN */
    emit_u(0x7f800001u); /* sNaN */
    emit_u(0xffc00000u); /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u); /* +Inf */
    emit_u(0xff800000u); /* -Inf */
}

/* 2. Tiny values: log10(x) for x near 0 */
static void test_tiny(void)
{
    emit_u(0x00000001u); /* min denorm */
    emit_u(0x80000001u);
    emit_u(0x00400000u); /* mid denorm */
    emit_u(0x80400000u);
    emit_u(0x007fffffu); /* max denorm */
    emit_u(0x807fffffu);
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(1.0e-20f);
    emit(-1.0e-20f);
    emit(1.0e-10f);
    emit(-1.0e-10f);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    float log10_2    = 0.30102999566398119522f;  /* log10(2) */
    float log10_e    = 0.43429448190325182765f;  /* log10(e) */
    float inv_log10e = 2.30258509299404568402f;  /* 1/log10(e) = ln(10) */

    emit(2.0f);       /* log10(2) */
    emit(10.0f);      /* log10(10) -> 1 */
    emit(1.0f);       /* log10(1) -> 0 */
    emit(100.0f);     /* log10(100) -> 2 */
    emit(1000.0f);    /* log10(1000) -> 3 */
    emit(0.1f);       /* log10(0.1) -> -1 */
    emit(0.01f);      /* log10(0.01) -> -2 */
    emit(0.001f);     /* log10(0.001) -> -3 */
    emit(0.5f);
    emit(5.0f);
    emit(log10_2);    /* log10(log10(2)) */
    emit(log10_e);    /* log10(log10(e)) */
    emit(inv_log10e); /* log10(ln(10)) */
}

/* 4. Large arguments */
static void test_large(void)
{
    float vals[] = {
        1.0e10f, 1.0e20f, FLT_MAX,
        10.0f, 100.0f, 1000.0f, 10000.0f, 100000.0f,
        -1.0f, -10.0f, -100.0f, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Powers of 10 (simple log10 values) and values near 1.0 */
static void test_quadrant(void)
{
    float one = 1.0f;
    float offsets[] = { -1e-5f, -1e-6f, 0.0f, 1e-6f, 1e-5f };
    int noff = sizeof(offsets) / sizeof(offsets[0]);

    for (int j = 0; j < noff; j++)
        emit(one + offsets[j]);

    /* Powers of 10 (simple log10 values) */
    float powers[] = { 0.001f, 0.01f, 0.1f, 1.0f, 10.0f, 100.0f, 1000.0f, 10000.0f, 100000.0f, 1000000.0f };
    int npow = sizeof(powers) / sizeof(powers[0]);
    for (int k = 0; k < npow; k++)
        emit(powers[k]);
}

/* 6. Worst-case argument values */
static void test_hard(void)
{
    float cases[] = {
        u2f(0x3f800001u), /* 1.0 + ULP, near log10(1)=0 */
        u2f(0x3f7fffffu), /* just below 1.0 */
        u2f(0x41200000u), /* 10.0 */
        u2f(0x42200000u), /* 40.0 */
        u2f(0x42c80000u), /* 100.0 */
        0.999999940f,      /* near 1.0 */
        1.000000060f,
        2.0f, 5.0f, 20.0f, 50.0f, 200.0f, 500.0f,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        if (cases[i] > 0.0f)
            emit(-cases[i]);
    }
}

/* 7. Sweep [1, 10] in 200 steps */
static void test_sweep(void)
{
    float lo = 1.0f;
    float hi = 10.0f;
    int nsteps = 200;
    float step = (hi - lo) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (float)i * step);
}

/* 8. Sample [1, 2] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t start = 0x3f800000u; /* 1.0 */
    uint32_t end   = 0x40000000u; /* 2.0 */
    for (uint32_t b = start; b <= end; b += 4194304)
        emit_u(b);
}

/* 9. Random sweep: 300 evenly spaced inputs */
static void test_random_300(void)
{
    int n = 300;
    for (int i = 0; i < n; i++) {
        float x = 1e-10f * powf(1e20f, (float)i / (float)(n - 1));
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(float x)
{
    volatile float acc = 0.0f;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += log10f(x+i);
    stopPFM;
    readResult();
    printf("perf %08lx: %08lx\n",
           (unsigned long)f2u(x),
           (unsigned long)f2u((float)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(2.0f);
#else
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_quadrant();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    test_random_300();
#endif
    return 0;
}

/*
 * pow() test harness — prints (x_hex, y_hex, output_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly pow  (test_pow_opt.elf)
 *   2. Linked with toolchain's default pow       (test_pow_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifndef EN_PERF
static void emit(double x, double y)
{
    double r = pow(x, y);
    printf("%016llx %016llx %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u(y),
           (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits_x, uint64_t bits_y)
{
    emit(u2d(bits_x), u2d(bits_y));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Base = 0 */
    emit(0.0, 0.5);
    emit(-0.0, 0.5);
    emit(0.0, 2.0);

    /* Base = 1 (identity) */
    emit(1.0, 0.0);
    emit(1.0, 2.0);
    emit(1.0, -2.0);
    emit(1.0, 100.0);

    /* Exponent = 0 (result always 1) */
    emit(2.0, 0.0);
    emit(10.0, 0.0);
    emit(-5.0, 0.0);

    /* NaN and Inf cases */
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL); /* qNaN base */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL); /* qNaN exp */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL); /* +Inf base */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL); /* -Inf base */
}

/* 2. Tiny values */
static void test_tiny(void)
{
    /* Small bases with small exponents */
    emit_u(0x0000000000000001ULL, 0x3ff0000000000000ULL); /* min denorm, exp=1 */
    emit(1.0e-150, 2.0);
    emit(1.0e-150, 0.5);
    emit(1.0e-50, 10.0);
    emit(DBL_MIN, 2.0);
    emit(DBL_MIN, 0.5);

    /* Tiny exponents */
    emit(2.0, 1.0e-100);
    emit(10.0, 1.0e-150);
}

/* 3. Known mathematical values (Pythagorean relations) */
static void test_known(void)
{
    /* Base and exponent pairs: (3,2)=9, (4,2)=16, (5,2)=25 (3-4-5 triple squared) */
    emit(3.0, 2.0);   /* 9 */
    emit(4.0, 2.0);   /* 16 */
    emit(5.0, 2.0);   /* 25 (sqrt(9+16)) */

    /* Base and exponent pairs: (5,2)=25, (12,2)=144, (13,2)=169 (5-12-13 triple squared) */
    emit(5.0, 2.0);   /* 25 */
    emit(12.0, 2.0);  /* 144 */
    emit(13.0, 2.0);  /* 169 */

    /* Powers of 2 */
    emit(2.0, 1.0);
    emit(2.0, 2.0);
    emit(2.0, 3.0);
    emit(2.0, 4.0);
    emit(2.0, 8.0);
    emit(2.0, 10.0);
    emit(2.0, -1.0);
    emit(2.0, -2.0);

    /* Powers of 10 */
    emit(10.0, 1.0);
    emit(10.0, 2.0);
    emit(10.0, 3.0);
    emit(10.0, -1.0);
    emit(10.0, -2.0);

    /* Fractional exponents */
    emit(4.0, 0.5);    /* sqrt(4) = 2 */
    emit(8.0, 0.333333);  /* cbrt(8) ~ 2 */
    emit(16.0, 0.25);  /* 16^(1/4) = 2 */
}

/* 4. Large arguments */
static void test_large(void)
{
    double base_vals[] = {
        1.0e10, 1.0e100, DBL_MAX,
        2.0, 10.0, 100.0,
        -2.0, -10.0,
    };

    int nbases = sizeof(base_vals) / sizeof(base_vals[0]);
    for (int i = 0; i < nbases; i++) {
        emit(base_vals[i], 2.0);
        emit(base_vals[i], 0.5);
        emit(base_vals[i], -1.0);
    }
}

/* 5. Exponent magnitude sensitivity */
static void test_exponent_range(void)
{
    /* Base 2 with various exponents */
    double exps[] = { -100.0, -10.0, -1.0, -0.5, 0.0, 0.5, 1.0, 10.0, 100.0 };
    int nexps = sizeof(exps) / sizeof(exps[0]);

    for (int i = 0; i < nexps; i++) {
        emit(2.0, exps[i]);
        emit(0.5, exps[i]);
        emit(10.0, exps[i]);
    }
}

/* 6. Worst-case rounding */
static void test_hard(void)
{
    double cases[][2] = {
        { 2.0, 2.0 },
        { 2.0, 3.0 },
        { 3.0, 2.0 },
        { 3.0, 3.0 },
        { 1.5, 4.0 },
        { 1.5, -4.0 },
        { u2d(0x3ff0000000000000ULL), u2d(0x4000000000000000ULL) }, /* 1.0, 2.0 */
        { u2d(0x4000000000000000ULL), u2d(0x4000000000000000ULL) }, /* 2.0, 2.0 */
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i][0], cases[i][1]);
        emit(-cases[i][0], cases[i][1]);
    }
}

/* 7. Sweep base [0.5, 10] and exponent [0, 5] */
static void test_sweep(void)
{
    int nbase = 50;
    int nexp = 50;

    for (int i = 0; i <= nbase; i++) {
        double base = 0.5 + (10.0 - 0.5) * (double)i / (double)nbase;
        for (int j = 0; j <= nexp; j++) {
            double exp = (double)j * 5.0 / (double)nexp;
            emit(base, exp);
        }
    }
}

/* 8. Sample critical range with ULP granularity */
static void test_exhaustive_small(void)
{
    /* Base in [1.0, 2.0], exponent in [0, 1] */
    uint64_t base_start = 0x3ff0000000000000ULL; /* 1.0 */
    uint64_t base_end = 0x4000000000000000ULL;   /* 2.0 */
    uint64_t exp_start = 0x0000000000000000ULL;  /* 0.0 */
    uint64_t exp_end = 0x3ff0000000000000ULL;    /* 1.0 */
    int nsteps = 16;

    for (int i = 0; i <= nsteps; i++) {
        double base = u2d(base_start) + (u2d(base_end) - u2d(base_start)) * (double)i / (double)nsteps;
        for (int j = 0; j <= nsteps; j++) {
            double exp = u2d(exp_start) + (u2d(exp_end) - u2d(exp_start)) * (double)j / (double)nsteps;
            emit(base, exp);
        }
    }
}

/* 9. Random sweep: 15x20 grid = 300 cases */
static void test_random_300(void)
{
    int nx = 15, ny = 20;
    for (int i = 0; i < nx; i++) {
        double x = 0.5 + 9.5 * (double)i / (double)(nx - 1);
        for (int j = 0; j < ny; j++) {
            double y = -3.0 + 6.0 * (double)j / (double)(ny - 1);
            emit(x, y);
        }
    }
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(double x)
{
    volatile double acc = 0.0;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += pow(x+i, 0.5);
    stopPFM;
