     1→/*
     2→ * floorf() test harness — prints (input_hex, output_hex) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly floorf  (test_floorf_opt.elf)
     6→ *   2. Linked with toolchain's default floorf        (test_floorf_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→static inline uint32_t f2u(float f)
    16→{
    17→    union { float f; uint32_t u; } x;
    18→    x.f = f;
    19→    return x.u;
    20→}
    21→
    22→static inline float u2f(uint32_t u)
    23→{
    24→    union { float f; uint32_t u; } x;
    25→    x.u = u;
    26→    return x.f;
    27→}
    28→
    29→static void emit(float x)
    30→{
    31→    float r = floorf(x);
    32→    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
    33→}
    34→
    35→static void emit_u(uint32_t bits)
    36→{
    37→    emit(u2f(bits));
    38→}
    39→
    40→/* ------------------------------------------------------------------ */
    41→/* Test points                                                         */
    42→/* ------------------------------------------------------------------ */
    43→
    44→/* 1. Special values */
    45→static void test_special(void)
    46→{
    47→    /* Zeros */
    48→    emit(0.0f);
    49→    emit(-0.0f);
    50→
    51→    /* NaN */
    52→    emit_u(0x7fc00000u); /* qNaN */
    53→    emit_u(0x7f800001u); /* sNaN */
    54→    emit_u(0xffc00000u); /* -NaN */
    55→
    56→    /* Infinity */
    57→    emit_u(0x7f800000u); /* +Inf */
    58→    emit_u(0xff800000u); /* -Inf */
    59→}
    60→
    61→/* 2. Tiny values: floor(x) ~ 0 for x > 0, -1 for x < 0 */
    62→static void test_tiny(void)
    63→{
    64→    emit_u(0x00000001u); /* min denorm */
    65→    emit_u(0x80000001u);
    66→    emit_u(0x00400000u); /* mid denorm */
    67→    emit_u(0x80400000u);
    68→    emit_u(0x007fffffu); /* max denorm */
    69→    emit_u(0x807fffffu);
    70→    emit(FLT_MIN);
    71→    emit(-FLT_MIN);
    72→    emit(1.0e-20f);
    73→    emit(-1.0e-20f);
    74→    emit(1.0e-10f);
    75→    emit(-1.0e-10f);
    76→}
    77→
    78→/* 3. Integer boundaries with fractional offsets */
    79→static void test_known(void)
    80→{
    81→    float vals[] = {
    82→        -2.5f, -2.0f, -1.5f, -1.0f, -0.5f, 0.0f,
    83→        0.5f, 1.0f, 1.5f, 2.0f, 2.5f,
    84→        3.1f, 4.9f, 5.0f, 5.1f,
    85→    };
    86→    int n = sizeof(vals) / sizeof(vals[0]);
    87→    for (int i = 0; i < n; i++)
    88→        emit(vals[i]);
    89→}
    90→
    91→/* 4. Large integer and fractional values */
    92→static void test_large(void)
    93→{
    94→    float vals[] = {
    95→        10.0f, 10.1f, 10.9f,
    96→        100.0f, 100.5f,
    97→        1000.0f, 1000.1f,
    98→        1.0e10f, 1.0e10f + 0.5f,
    99→        -10.0f, -10.1f, -10.9f,
   100→        -100.0f, -100.5f,
   101→        FLT_MAX, -FLT_MAX,
   102→    };
   103→    int n = sizeof(vals) / sizeof(vals[0]);
   104→    for (int i = 0; i < n; i++)
   105→        emit(vals[i]);
   106→}
   107→
   108→/* 5. Boundaries with precise offsets */
   109→static void test_boundaries(void)
   110→{
   111→    for (int i = 0; i < 10; i++) {
   112→        float base = (float)i;
   113→        emit(base - 0.5f);
   114→        emit(base);
   115→        emit(base + 0.5f);
   116→    }
   117→
   118→    for (int i = 0; i > -10; i--) {
   119→        float base = (float)i;
   120→        emit(base - 0.5f);
   121→        emit(base);
   122→        emit(base + 0.5f);
   123→    }
   124→}
   125→
   126→/* 6. Worst-case argument values */
   127→static void test_hard(void)
   128→{
   129→    float cases[] = {
   130→        0.125f, 0.25f, 0.375f, 0.625f, 0.75f, 0.875f,
   131→        u2f(0x3f490fdbu), /* pi/4 */
   132→        u2f(0x3fc90fdbu), /* pi/2 */
   133→        u2f(0x4049cbe4u), /* 3*pi/2 */
   134→    };
   135→    int n = sizeof(cases) / sizeof(cases[0]);
   136→    for (int i = 0; i < n; i++) {
   137→        emit(cases[i]);
   138→        emit(-cases[i]);
   139→    }
   140→}
   141→
   142→/* 7. Sweep [0, 10] in 200 steps */
   143→static void test_sweep(void)
   144→{
   145→    float hi = 10.0f;
   146→    int nsteps = 200;
   147→    float step = hi / (float)nsteps;
   148→
   149→    /* [0, 10] */
   150→    for (int i = 0; i <= nsteps; i++)
   151→        emit((float)i * step);
   152→
   153→    /* [-10, 0] */
   154→    for (int i = 0; i <= nsteps; i++)
   155→        emit(-hi + (float)i * step);
   156→}
   157→
   158→/* 8. Sample [0, 1] every 4194304 ULP (~250 cases) */
   159→static void test_exhaustive_small(void)
   160→{
   161→    uint32_t end = 0x3f800000u; /* 1.0 */
   162→    for (uint32_t b = 0; b <= end; b += 4194304)
   163→        emit_u(b);
   164→}
   165→
   166→/* 9. Random sweep: 300 evenly spaced inputs */
   167→static void test_random_300(void)
   168→{
   169→    float lo = -50.0f;
   170→    float hi =  50.0f;
   171→    int n = 300;
   172→    for (int i = 0; i < n; i++) {
   173→        float x = lo + (hi - lo) * (float)i / (float)(n - 1);
   174→        emit(x);
   175→    }
   176→}
   177→
   178→/* ------------------------------------------------------------------ */
   179→
   180→int main(void)
   181→{
   182→    test_special();
   183→    test_tiny();
   184→    test_known();
   185→    test_large();
   186→    test_boundaries();
   187→    test_hard();
   188→    test_sweep();
   189→    test_exhaustive_small();
   190→    test_random_300();
   191→    return 0;
   192→}
